function TokenBucket(capacity, refillPerSec) {
  let tokens = capacity;
  let last = Date.now();
  return {
    allow() {
      const now = Date.now();
      const elapsed = (now - last) / 1000;
      tokens = Math.min(capacity, tokens + elapsed * refillPerSec);
      last = now;
      if (tokens >= 1) { tokens -= 1; return { ok: true, retryAfter: 0 }; }
      return { ok: false, retryAfter: Math.ceil((1 - tokens) / refillPerSec) };
    },
  };
}

function idempotentStore() {
  const map = new Map();
  return {
    execute(key, fn) {
      if (map.has(key)) return { duplicate: true, result: map.get(key) };
      const result = fn();
      map.set(key, result);
      return { duplicate: false, result };
    },
  };
}

