function lsm() {
  let mem = new Map();
  const sst = [];
  return {
    put(k, v) { mem.set(k, v); },
    del(k) { mem.set(k, null); },
    flush() { const sorted = [...mem.entries()].sort((a, b) => a[0].localeCompare(b[0])); sst.unshift(sorted); mem = new Map(); },
    get(k) {
      if (mem.has(k)) return mem.get(k);
      for (const file of sst) {
        const hit = file.find(([key]) => key === k);
        if (hit) return hit[1];
      }
      return undefined;
    },
  };
}

